    38→// handleError writes a standardized JSON error response with the given status code.
    39→// It logs the error at WARN level and ensures proper Content-Type headers are set.
    40→func handleError(err error, statusCode int, rw http.ResponseWriter) {
    41→	cclog.Warnf("REST ERROR : %s", err.Error())
    42→	rw.Header().Add("Content-Type", "application/json")
    43→	rw.WriteHeader(statusCode)
    44→	if err := json.NewEncoder(rw).Encode(ErrorResponse{
    45→		Status: http.StatusText(statusCode),
    46→		Error:  err.Error(),
    47→	}); err != nil {
    48→		cclog.Errorf("Failed to encode error response: %v", err)
    49→	}
    50→}
