    52→type APIMetricData struct {
    53→	Error      *string           `json:"error,omitempty"`
    54→	Data       schema.FloatArray `json:"data,omitempty"`
    55→	From       int64             `json:"from"`
    56→	To         int64             `json:"to"`
    57→	Resolution int64             `json:"resolution"`
    58→	Avg        schema.Float      `json:"avg"`
    59→	Min        schema.Float      `json:"min"`
    60→	Max        schema.Float      `json:"max"`
    61→}
    62→
    63→// TODO: Optimize this, just like the stats endpoint!
    64→func (data *APIMetricData) AddStats() {
    65→	n := 0
    66→	sum, min, max := 0.0, math.MaxFloat64, -math.MaxFloat64
    67→	for _, x := range data.Data {
    68→		if x.IsNaN() {
    69→			continue
    70→		}
    71→
    72→		n += 1
    73→		sum += float64(x)
    74→		min = math.Min(min, float64(x))
    75→		max = math.Max(max, float64(x))
    76→	}
    77→
    78→	if n > 0 {
    79→		avg := sum / float64(n)
    80→		data.Avg = schema.Float(avg)
    81→		data.Min = schema.Float(min)
    82→		data.Max = schema.Float(max)
    83→	} else {
    84→		data.Avg, data.Min, data.Max = schema.NaN, schema.NaN, schema.NaN
    85→	}
    86→}
    87→
    88→func (data *APIMetricData) ScaleBy(f schema.Float) {
    89→	if f == 0 || f == 1 {
    90→		return
    91→	}
    92→
    93→	data.Avg *= f
    94→	data.Min *= f
    95→	data.Max *= f
    96→	for i := 0; i < len(data.Data); i++ {
    97→		data.Data[i] *= f
    98→	}
    99→}
   100→
   101→func (data *APIMetricData) PadDataWithNull(ms *metricstore.MemoryStore, from, to int64, metric string) {
   102→	minfo, ok := ms.Metrics[metric]
   103→	if !ok {
   104→		return
   105→	}
   106→
   107→	if (data.From / minfo.Frequency) > (from / minfo.Frequency) {
   108→		padfront := int((data.From / minfo.Frequency) - (from / minfo.Frequency))
   109→		ndata := make([]schema.Float, 0, padfront+len(data.Data))
   110→		for range padfront {
   111→			ndata = append(ndata, schema.NaN)
   112→		}
   113→		for j := 0; j < len(data.Data); j++ {
   114→			ndata = append(ndata, data.Data[j])
   115→		}
   116→		data.Data = ndata
   117→	}
   118→}
