   136→type APIQuery struct {
   137→	Type        *string      `json:"type,omitempty"`
   138→	SubType     *string      `json:"subtype,omitempty"`
   139→	Metric      string       `json:"metric"`
   140→	Hostname    string       `json:"host"`
