   344→// handleWrite godoc
   345→// @summary Receive metrics in InfluxDB line-protocol
   346→// @tags write
   347→// @description Write data to the in-memory store in the InfluxDB line-protocol using [this format](https://github.com/ClusterCockpit/cc-specifications/blob/master/metrics/lineprotocol_alternative.md)
   348→
   349→// @accept      plain
   350→// @produce     json
   351→// @param       cluster        query string false "If the lines in the body do not have a cluster tag, use this value instead."
   352→// @success     200            {string} string  "ok"
   353→// @failure     400            {object} api.ErrorResponse       "Bad Request"
