   408→// @summary HealthCheck endpoint
   409→// @tags healthcheck
   410→// @description This endpoint allows the users to check if a node is healthy
   411→// @produce     json
   412→// @param       selector        query    string            false "Selector"
   413→// @success     200            {string} string  "Debug dump"
   414→// @failure     400            {object} api.ErrorResponse       "Bad Request"
   415→// @failure     401            {object} api.ErrorResponse       "Unauthorized"
   416→// @failure     403            {object} api.ErrorResponse       "Forbidden"
   417→// @failure     500            {object} api.ErrorResponse       "Internal Server Error"
   418→// @security    ApiKeyAuth
   419→// @router      /healthcheck/ [get]
   420→func metricsHealth(rw http.ResponseWriter, r *http.Request) {
   421→	req := metricstore.HealthCheckReq{}
   422→
   423→	dec := json.NewDecoder(r.Body)
   424→	dec.DisallowUnknownFields()
   425→
   426→	if err := dec.Decode(&req); err != nil {
   427→		handleError(fmt.Errorf("parsing request body failed: %w", err),
   428→			http.StatusBadRequest, rw)
   429→		return
   430→	}
   431→
   432→	rw.Header().Add("Content-Type", "application/json")
   433→
   434→	ms := metricstore.GetMemoryStore()
   435→	results, err := ms.HealthCheck(req.Cluster, req.Nodes, req.MetricNames)
   436→	if err != nil {
   437→		handleError(err, http.StatusBadRequest, rw)
   438→		return
   439→	}
   440→
   441→	rw.Header().Set("Content-Type", "application/json")
   442→	bw := bufio.NewWriter(rw)
   443→	defer bw.Flush()
   444→	if err := json.NewEncoder(bw).Encode(results); err != nil {
   445→		log.Print(err)
   446→		return
   447→	}
   448→}
   449→
   450→// queryParam extracts a single query parameter value from a raw query string
   451→// without allocating a url.Values map.
   452→func queryParam(rawQuery, key string) string {
   453→	for rawQuery != "" {
   454→		var kv string
   455→		if before, after, ok := strings.Cut(rawQuery, "&"); ok {
   456→			kv, rawQuery = before, after
   457→		} else {
   458→			kv, rawQuery = rawQuery, ""
   459→		}
   460→		if before, after, ok := strings.Cut(kv, "="); ok {
   461→			if before == key {
   462→				return after
   463→			}
   464→		} else if kv == key {
   465→			return ""
   466→		}
   467→	}
   468→	return ""
   469→}
