    52→	"time"
    53→
    54→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
    55→	"github.com/ClusterCockpit/cc-lib/v2/schema"
    56→)
    57→
    58→const (
    59→	CheckpointFilePerms = 0o644                    // File permissions for checkpoint files
    60→	CheckpointDirPerms  = 0o755                    // Directory permissions for checkpoint directories
    61→	GCTriggerInterval   = DefaultGCTriggerInterval // Interval for triggering GC during checkpoint loading
    62→)
    63→
    64→// CheckpointMetrics represents metric data in a checkpoint file.
    65→// Whenever the structure changes, update MarshalJSON as well!
    66→type CheckpointMetrics struct {
    67→	Data      []schema.Float `json:"data"`
    68→	Frequency int64          `json:"frequency"`
    69→	Start     int64          `json:"start"`
    70→}
    71→
    72→// CheckpointFile represents the hierarchical structure of a checkpoint file.
    73→// It mirrors the Level tree structure from the MemoryStore.
    74→type CheckpointFile struct {
    75→	Metrics  map[string]*CheckpointMetrics `json:"metrics"`
    76→	Children map[string]*CheckpointFile    `json:"children"`
    77→	From     int64                         `json:"from"`
    78→	To       int64                         `json:"to"`
    79→}
    80→
    81→// lastCheckpoint tracks the timestamp of the last checkpoint creation.
    82→var (
    83→	lastCheckpoint   time.Time
    84→	lastCheckpointMu sync.Mutex
    85→)
    86→
    87→// Checkpointing starts a background worker that periodically saves metric data to disk.
    88→//
    89→// Format behaviour:
    90→//   - "json": Periodic checkpointing based on Keys.Checkpoints.Interval
    91→//   - "wal":  Periodic binary snapshots + WAL rotation at Keys.Checkpoints.Interval
    92→func Checkpointing(wg *sync.WaitGroup, ctx context.Context) {
    93→	lastCheckpointMu.Lock()
    94→	lastCheckpoint = time.Now()
    95→	lastCheckpointMu.Unlock()
    96→
    97→	ms := GetMemoryStore()
    98→
    99→	wg.Go(func() {
   100→
   101→		d, err := time.ParseDuration(Keys.Checkpoints.Interval)
   102→		if err != nil {
   103→			cclog.Fatalf("[METRICSTORE]> invalid checkpoint interval '%s': %s", Keys.Checkpoints.Interval, err.Error())
   104→		}
   105→		if d <= 0 {
   106→			cclog.Warnf("[METRICSTORE]> checkpoint interval is zero or negative (%s), checkpointing disabled", d)
   107→			return
   108→		}
   109→
   110→		ticker := time.NewTicker(d)
   111→		defer ticker.Stop()
   112→
   113→		for {
   114→			select {
   115→			case <-ctx.Done():
   116→				return
   117→			case <-ticker.C:
   118→				lastCheckpointMu.Lock()
   119→				from := lastCheckpoint
   120→				lastCheckpointMu.Unlock()
   121→
   122→				now := time.Now()
   123→				cclog.Infof("[METRICSTORE]> start checkpointing (starting at %s)...", from.Format(time.RFC3339))
   124→
   125→				if Keys.Checkpoints.FileFormat == "wal" {
   126→					n, hostDirs, err := ms.ToCheckpointWAL(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
   127→					if err != nil {
   128→						cclog.Errorf("[METRICSTORE]> binary checkpointing failed: %s", err.Error())
   129→					} else {
   130→						cclog.Infof("[METRICSTORE]> done: %d binary snapshot files created", n)
   131→						lastCheckpointMu.Lock()
   132→						lastCheckpoint = now
   133→						lastCheckpointMu.Unlock()
   134→						// Rotate WAL files for successfully checkpointed hosts.
   135→						RotateWALFiles(hostDirs)
   136→					}
   137→				} else {
   138→					n, err := ms.ToCheckpoint(Keys.Checkpoints.RootDir, from.Unix(), now.Unix())
   139→					if err != nil {
   140→						cclog.Errorf("[METRICSTORE]> checkpointing failed: %s", err.Error())
   141→					} else {
   142→						cclog.Infof("[METRICSTORE]> done: %d checkpoint files created", n)
   143→						lastCheckpointMu.Lock()
   144→						lastCheckpoint = now
   145→						lastCheckpointMu.Unlock()
   146→					}
   147→				}
   148→			}
   149→		}
   150→	})
   151→}
