   153→// MarshalJSON provides optimized JSON encoding for CheckpointMetrics.
   154→//
   155→// Since schema.Float has custom MarshalJSON, serializing []Float has significant overhead.
   156→// This method manually constructs JSON to avoid allocations and interface conversions.
   157→func (cm *CheckpointMetrics) MarshalJSON() ([]byte, error) {
   158→	buf := make([]byte, 0, 128+len(cm.Data)*8)
   159→	buf = append(buf, `{"frequency":`...)
   160→	buf = strconv.AppendInt(buf, cm.Frequency, 10)
   161→	buf = append(buf, `,"start":`...)
   162→	buf = strconv.AppendInt(buf, cm.Start, 10)
   163→	buf = append(buf, `,"data":[`...)
   164→	for i, x := range cm.Data {
   165→		if i != 0 {
   166→			buf = append(buf, ',')
   167→		}
   168→		if x.IsNaN() {
   169→			buf = append(buf, `null`...)
   170→		} else {
   171→			buf = strconv.AppendFloat(buf, float64(x), 'f', 1, 32)
   172→		}
   173→	}
   174→	buf = append(buf, `]}`...)
   175→	return buf, nil
   176→}
   177→
   178→// ToCheckpoint writes metric data to checkpoint files in parallel (JSON format).
   179→//
   180→// Metrics at root and cluster levels are skipped. One file per host is created.
   181→// Uses worker pool (Keys.NumWorkers) for parallel processing. Only locks one host
   182→// at a time, allowing concurrent writes/reads to other hosts.
   183→//
   184→// Returns the number of checkpoint files created and any errors encountered.
   185→func (m *MemoryStore) ToCheckpoint(dir string, from, to int64) (int, error) {
   186→	// Pre-calculate capacity by counting cluster/host pairs
   187→	m.root.lock.RLock()
   188→	totalHosts := 0
   189→	for _, l1 := range m.root.children {
   190→		l1.lock.RLock()
   191→		totalHosts += len(l1.children)
   192→		l1.lock.RUnlock()
   193→	}
   194→	m.root.lock.RUnlock()
   195→
   196→	levels := make([]*Level, 0, totalHosts)
   197→	selectors := make([][]string, 0, totalHosts)
   198→
   199→	m.root.lock.RLock()
   200→	for sel1, l1 := range m.root.children {
   201→		l1.lock.RLock()
   202→		for sel2, l2 := range l1.children {
   203→			levels = append(levels, l2)
   204→			selectors = append(selectors, []string{sel1, sel2})
   205→		}
   206→		l1.lock.RUnlock()
   207→	}
   208→	m.root.lock.RUnlock()
   209→
   210→	type workItem struct {
   211→		level    *Level
   212→		dir      string
   213→		selector []string
   214→	}
   215→
   216→	n, errs := int32(0), int32(0)
   217→
   218→	var wg sync.WaitGroup
   219→	wg.Add(Keys.NumWorkers)
   220→	work := make(chan workItem, Keys.NumWorkers*2)
   221→	for worker := 0; worker < Keys.NumWorkers; worker++ {
   222→		go func() {
   223→			defer wg.Done()
   224→
   225→			for workItem := range work {
   226→				if err := workItem.level.toCheckpoint(workItem.dir, from, to, m); err != nil {
   227→					if err == ErrNoNewArchiveData {
   228→						continue
   229→					}
   230→
   231→					cclog.Errorf("[METRICSTORE]> error while checkpointing %#v: %s", workItem.selector, err.Error())
   232→					atomic.AddInt32(&errs, 1)
   233→				} else {
   234→					atomic.AddInt32(&n, 1)
   235→				}
   236→			}
   237→		}()
   238→	}
   239→
   240→	for i := 0; i < len(levels); i++ {
   241→		dir := path.Join(dir, path.Join(selectors[i]...))
   242→		work <- workItem{
   243→			level:    levels[i],
   244→			dir:      dir,
   245→			selector: selectors[i],
   246→		}
   247→	}
   248→
   249→	close(work)
   250→	wg.Wait()
   251→
   252→	if errs > 0 {
   253→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
   254→	}
   255→	return int(n), nil
   256→}
