   258→// toCheckpointFile recursively converts a Level tree to CheckpointFile structure.
   259→// Skips metrics that are already archived. Returns nil if no unarchived data exists.
   260→func (l *Level) toCheckpointFile(from, to int64, m *MemoryStore) (*CheckpointFile, error) {
   261→	l.lock.RLock()
   262→	defer l.lock.RUnlock()
   263→
   264→	retval := &CheckpointFile{
   265→		From:     from,
   266→		To:       to,
   267→		Metrics:  make(map[string]*CheckpointMetrics),
   268→		Children: make(map[string]*CheckpointFile),
   269→	}
   270→
   271→	for metric, minfo := range m.Metrics {
   272→		b := l.metrics[minfo.offset]
   273→		if b == nil {
   274→			continue
   275→		}
   276→
   277→		allArchived := true
   278→		b.iterFromTo(from, to, func(b *buffer) error {
   279→			if !b.archived {
   280→				allArchived = false
   281→				return fmt.Errorf("stop") // Early termination signal
   282→			}
   283→			return nil
   284→		})
   285→
   286→		if allArchived {
   287→			continue
   288→		}
   289→
   290→		data := make([]schema.Float, (to-from)/b.frequency+1)
   291→		data, start, end, err := b.read(from, to, data)
   292→		if err != nil {
   293→			return nil, err
   294→		}
   295→
   296→		for i := int((end - start) / b.frequency); i < len(data); i++ {
   297→			data[i] = schema.NaN
   298→		}
   299→
   300→		retval.Metrics[metric] = &CheckpointMetrics{
   301→			Frequency: b.frequency,
   302→			Start:     start,
   303→			Data:      data,
   304→		}
   305→	}
   306→
   307→	for name, child := range l.children {
   308→		val, err := child.toCheckpointFile(from, to, m)
   309→		if err != nil {
   310→			return nil, err
   311→		}
   312→
   313→		if val != nil {
   314→			retval.Children[name] = val
   315→		}
   316→	}
   317→
   318→	if len(retval.Children) == 0 && len(retval.Metrics) == 0 {
   319→		return nil, nil
   320→	}
   321→
   322→	return retval, nil
   323→}
   324→
   325→// toCheckpoint writes a Level's data to a JSON checkpoint file.
   326→// Creates directory if needed. Returns ErrNoNewArchiveData if nothing to save.
   327→func (l *Level) toCheckpoint(dir string, from, to int64, m *MemoryStore) error {
   328→	cf, err := l.toCheckpointFile(from, to, m)
   329→	if err != nil {
   330→		return err
   331→	}
   332→
   333→	if cf == nil {
   334→		return ErrNoNewArchiveData
   335→	}
   336→
   337→	filepath := path.Join(dir, fmt.Sprintf("%d.json", from))
   338→	f, err := os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
   339→	if err != nil && os.IsNotExist(err) {
   340→		err = os.MkdirAll(dir, CheckpointDirPerms)
   341→		if err == nil {
   342→			f, err = os.OpenFile(filepath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
   343→		}
   344→	}
   345→	if err != nil {
   346→		return err
   347→	}
   348→	defer f.Close()
   349→
   350→	bw := bufio.NewWriter(f)
   351→	if err = json.NewEncoder(bw).Encode(cf); err != nil {
   352→		return err
   353→	}
   354→
   355→	return bw.Flush()
   356→}
   357→
   358→// enqueueCheckpointHosts traverses checkpoint directory and enqueues cluster/host pairs.
   359→// Returns error if directory structure is invalid.
   360→func enqueueCheckpointHosts(dir string, work chan<- [2]string) error {
   361→	clustersDir, err := os.ReadDir(dir)
   362→	if err != nil {
   363→		return err
   364→	}
   365→
   366→	for _, clusterDir := range clustersDir {
   367→		if !clusterDir.IsDir() {
   368→			return errors.New("[METRICSTORE]> expected only directories at first level of checkpoints/ directory")
   369→		}
   370→
   371→		hostsDir, err := os.ReadDir(filepath.Join(dir, clusterDir.Name()))
   372→		if err != nil {
   373→			return err
   374→		}
   375→
   376→		for _, hostDir := range hostsDir {
   377→			if !hostDir.IsDir() {
   378→				return errors.New("[METRICSTORE]> expected only directories at second level of checkpoints/ directory")
   379→			}
   380→
   381→			work <- [2]string{clusterDir.Name(), hostDir.Name()}
   382→		}
   383→	}
   384→
   385→	return nil
   386→}
   387→
   388→// FromCheckpoint loads checkpoint files from disk into memory in parallel.
   389→//
   390→// Uses worker pool to load cluster/host combinations. Returns number of files
   391→// loaded and any errors.
   392→func (m *MemoryStore) FromCheckpoint(dir string, from int64) (int, error) {
   393→	var wg sync.WaitGroup
   394→	work := make(chan [2]string, Keys.NumWorkers*4)
   395→	n, errs := int32(0), int32(0)
   396→
   397→	wg.Add(Keys.NumWorkers)
   398→	for worker := 0; worker < Keys.NumWorkers; worker++ {
   399→		go func() {
   400→			defer wg.Done()
   401→			for host := range work {
   402→				lvl := m.root.findLevelOrCreate(host[:], len(m.Metrics))
   403→				nn, err := lvl.fromCheckpoint(m, filepath.Join(dir, host[0], host[1]), from)
   404→				if err != nil {
   405→					cclog.Errorf("[METRICSTORE]> error while loading checkpoints for %s/%s: %s", host[0], host[1], err.Error())
   406→					atomic.AddInt32(&errs, 1)
   407→				}
   408→				atomic.AddInt32(&n, int32(nn))
   409→			}
   410→		}()
   411→	}
   412→
   413→	err := enqueueCheckpointHosts(dir, work)
   414→	close(work)
   415→	wg.Wait()
   416→
   417→	if err != nil {
   418→		return int(n), err
   419→	}
   420→
   421→	if errs > 0 {
   422→		return int(n), fmt.Errorf("[METRICSTORE]> %d errors happened while creating checkpoints (%d successes)", errs, n)
   423→	}
   424→	return int(n), nil
   425→}
   426→
   427→// FromCheckpointFiles is the main entry point for loading checkpoints at startup.
   428→//
   429→// Creates checkpoint directory if it doesn't exist. This function must be called
   430→// before any writes or reads, and can only be called once.
   431→func (m *MemoryStore) FromCheckpointFiles(dir string, from int64) (int, error) {
   432→	if _, err := os.Stat(dir); os.IsNotExist(err) {
   433→		err := os.MkdirAll(dir, CheckpointDirPerms)
   434→		if err != nil {
   435→			cclog.Fatalf("[METRICSTORE]> Error creating directory: %#v\n", err)
   436→		}
   437→		cclog.Debugf("[METRICSTORE]> %#v Directory created successfully", dir)
   438→	}
   439→
   440→	return m.FromCheckpoint(dir, from)
   441→}
   442→
   443→func (l *Level) loadJSONFile(m *MemoryStore, f *os.File, from int64) error {
   444→	br := bufio.NewReader(f)
   445→	cf := &CheckpointFile{}
   446→	if err := json.NewDecoder(br).Decode(cf); err != nil {
   447→		return err
   448→	}
   449→
   450→	if cf.To != 0 && cf.To < from {
   451→		return nil
   452→	}
   453→
   454→	if err := l.loadFile(cf, m); err != nil {
   455→		return err
   456→	}
   457→
   458→	return nil
   459→}
   460→
   461→func (l *Level) loadFile(cf *CheckpointFile, m *MemoryStore) error {
   462→	for name, metric := range cf.Metrics {
   463→		n := len(metric.Data)
   464→		b := &buffer{
   465→			frequency: metric.Frequency,
   466→			start:     metric.Start,
   467→			data:      metric.Data[0:n:n],
   468→			prev:      nil,
   469→			next:      nil,
   470→			archived:  true,
   471→		}
   472→
   473→		minfo, ok := m.Metrics[name]
   474→		if !ok {
   475→			continue
   476→		}
   477→
   478→		prev := l.metrics[minfo.offset]
   479→		if prev == nil {
   480→			l.metrics[minfo.offset] = b
   481→		} else {
   482→			if prev.start > b.start {
   483→				return fmt.Errorf("[METRICSTORE]> buffer start time %d is before previous buffer start %d", b.start, prev.start)
   484→			}
   485→
   486→			b.prev = prev
   487→			prev.next = b
   488→		}
   489→		l.metrics[minfo.offset] = b
   490→	}
   491→
   492→	if len(cf.Children) > 0 && l.children == nil {
   493→		l.children = make(map[string]*Level)
   494→	}
   495→
   496→	for sel, childCf := range cf.Children {
   497→		child, ok := l.children[sel]
   498→		if !ok {
   499→			child = &Level{
   500→				metrics:  make([]*buffer, len(m.Metrics)),
   501→				children: nil,
   502→			}
   503→			l.children[sel] = child
   504→		}
   505→
   506→		if err := child.loadFile(childCf, m); err != nil {
   507→			return err
   508→		}
   509→	}
   510→
   511→	return nil
   512→}
   513→
   514→// fromCheckpoint loads all checkpoint files (JSON, binary snapshot, WAL) for a
   515→// single host directory. Snapshot files are loaded first (sorted by timestamp),
   516→// then current.wal is replayed on top.
   517→func (l *Level) fromCheckpoint(m *MemoryStore, dir string, from int64) (int, error) {
   518→	direntries, err := os.ReadDir(dir)
   519→	if err != nil {
   520→		if os.IsNotExist(err) {
   521→			return 0, nil
   522→		}
   523→		return 0, err
   524→	}
   525→
   526→	allFiles := make([]fs.DirEntry, 0)
   527→	var walEntry fs.DirEntry
   528→	filesLoaded := 0
   529→
   530→	for _, e := range direntries {
   531→		if e.IsDir() {
   532→			// Legacy: skip subdirectories (only used by old Avro format).
   533→			// These are ignored; their data is not loaded.
   534→			cclog.Debugf("[METRICSTORE]> skipping subdirectory %s in checkpoint dir %s", e.Name(), dir)
   535→			continue
   536→		}
   537→
   538→		name := e.Name()
   539→		if strings.HasSuffix(name, ".json") || strings.HasSuffix(name, ".bin") {
   540→			allFiles = append(allFiles, e)
   541→		} else if name == "current.wal" {
   542→			walEntry = e
   543→		}
   544→		// Silently ignore other files (e.g., .tmp, .bin.tmp from interrupted writes).
   545→	}
   546→
   547→	files, err := findFiles(allFiles, from, true)
   548→	if err != nil {
   549→		return filesLoaded, err
   550→	}
   551→
   552→	loaders := map[string]func(*MemoryStore, *os.File, int64) error{
   553→		".json": l.loadJSONFile,
   554→		".bin":  l.loadBinaryFile,
   555→	}
   556→
   557→	for _, filename := range files {
   558→		ext := filepath.Ext(filename)
   559→		loader := loaders[ext]
   560→		if loader == nil {
   561→			cclog.Warnf("[METRICSTORE]> unknown extension for checkpoint file %s", filename)
   562→			continue
   563→		}
   564→
   565→		err := func() error {
   566→			f, err := os.Open(path.Join(dir, filename))
   567→			if err != nil {
   568→				return err
   569→			}
   570→			defer f.Close()
   571→			return loader(m, f, from)
   572→		}()
   573→		if err != nil {
   574→			return filesLoaded, err
   575→		}
   576→		filesLoaded++
   577→	}
   578→
   579→	// Replay WAL after all snapshot files so it fills in data since the last snapshot.
   580→	if walEntry != nil {
   581→		err := func() error {
   582→			f, err := os.Open(path.Join(dir, walEntry.Name()))
   583→			if err != nil {
   584→				return err
   585→			}
   586→			defer f.Close()
   587→			return l.loadWALFile(m, f, from)
   588→		}()
   589→		if err != nil {
   590→			// WAL errors are non-fatal: the snapshot already loaded the bulk of data.
   591→			cclog.Warnf("[METRICSTORE]> WAL replay error for %s: %v (data since last snapshot may be missing)", dir, err)
   592→		} else {
   593→			filesLoaded++
   594→		}
   595→	}
   596→
   597→	return filesLoaded, nil
   598→}
   599→
   600→// parseTimestampFromFilename extracts a Unix timestamp from a checkpoint filename.
   601→// Supports ".json" (format: "<ts>.json") and ".bin" (format: "<ts>.bin").
   602→func parseTimestampFromFilename(name string) (int64, error) {
   603→	switch {
   604→	case strings.HasSuffix(name, ".json"):
   605→		return strconv.ParseInt(name[:len(name)-5], 10, 64)
   606→	case strings.HasSuffix(name, ".bin"):
   607→		return strconv.ParseInt(name[:len(name)-4], 10, 64)
   608→	default:
   609→		return 0, fmt.Errorf("unknown checkpoint extension for file %q", name)
   610→	}
   611→}
   612→
   613→// findFiles returns filenames from direntries whose timestamps satisfy the filter.
   614→// If findMoreRecentFiles is true, returns files with timestamps >= t (plus the
   615→// last file before t if t falls between two files).
   616→func findFiles(direntries []fs.DirEntry, t int64, findMoreRecentFiles bool) ([]string, error) {
   617→	nums := map[string]int64{}
   618→	for _, e := range direntries {
   619→		name := e.Name()
   620→		if !strings.HasSuffix(name, ".json") && !strings.HasSuffix(name, ".bin") {
   621→			continue
   622→		}
   623→
   624→		ts, err := parseTimestampFromFilename(name)
   625→		if err != nil {
   626→			return nil, err
   627→		}
   628→		nums[name] = ts
   629→	}
   630→
   631→	sort.Slice(direntries, func(i, j int) bool {
   632→		a, b := direntries[i], direntries[j]
   633→		return nums[a.Name()] < nums[b.Name()]
   634→	})
   635→
   636→	if len(nums) == 0 {
   637→		return nil, nil
   638→	}
   639→
   640→	filenames := make([]string, 0)
   641→
   642→	for i, e := range direntries {
   643→		ts1 := nums[e.Name()]
   644→
   645→		if findMoreRecentFiles && t <= ts1 {
   646→			filenames = append(filenames, e.Name())
   647→		} else if !findMoreRecentFiles && ts1 <= t && ts1 != 0 {
   648→			filenames = append(filenames, e.Name())
   649→		}
   650→
   651→		if i == len(direntries)-1 {
   652→			continue
   653→		}
   654→
   655→		enext := direntries[i+1]
   656→		ts2 := nums[enext.Name()]
   657→
   658→		if findMoreRecentFiles {
   659→			if ts1 < t && t < ts2 {
   660→				filenames = append(filenames, e.Name())
   661→			}
   662→		}
   663→	}
   664→
   665→	return filenames, nil
   666→}
