    19→
    20→// ParquetMetricRow is the long-format schema for archived metric data.
    21→// One row per (host, metric, scope, scope_id, timestamp) data point.
    22→// Sorted by (cluster, hostname, metric, timestamp) for optimal compression.
    23→type ParquetMetricRow struct {
    24→	Cluster   string  `parquet:"cluster"`
    25→	Hostname  string  `parquet:"hostname"`
    26→	Metric    string  `parquet:"metric"`
    27→	Scope     string  `parquet:"scope"`
    28→	ScopeID   string  `parquet:"scope_id"`
    29→	Timestamp int64   `parquet:"timestamp"`
    30→	Frequency int64   `parquet:"frequency"`
    31→	Value     float32 `parquet:"value"`
    32→}
    33→
    34→// flattenCheckpointFile recursively converts a CheckpointFile tree into Parquet rows.
    35→// The scope path is built from the hierarchy: host level is "node", then child names
    36→// map to scope/scope_id (e.g., "socket0" → scope="socket", scope_id="0").
    37→func flattenCheckpointFile(cf *CheckpointFile, cluster, hostname, scope, scopeID string, rows []ParquetMetricRow) []ParquetMetricRow {
    38→	for metricName, cm := range cf.Metrics {
    39→		ts := cm.Start
    40→		for _, v := range cm.Data {
    41→			if !v.IsNaN() {
    42→				rows = append(rows, ParquetMetricRow{
    43→					Cluster:   cluster,
    44→					Hostname:  hostname,
    45→					Metric:    metricName,
    46→					Scope:     scope,
    47→					ScopeID:   scopeID,
    48→					Timestamp: ts,
    49→					Frequency: cm.Frequency,
    50→					Value:     float32(v),
    51→				})
    52→			}
    53→			ts += cm.Frequency
    54→		}
    55→	}
    56→
    57→	for childName, childCf := range cf.Children {
    58→		childScope, childScopeID := parseScopeFromName(childName)
    59→		rows = flattenCheckpointFile(childCf, cluster, hostname, childScope, childScopeID, rows)
    60→	}
    61→
    62→	return rows
    63→}
    64→
    65→// parseScopeFromName infers scope and scope_id from a child level name.
    66→// Examples: "socket0" → ("socket", "0"), "core12" → ("core", "12"),
    67→// "a0" (accelerator) → ("accelerator", "0").
    68→// If the name doesn't match known patterns, it's used as-is for scope with empty scope_id.
    69→func parseScopeFromName(name string) (string, string) {
    70→	prefixes := []struct {
    71→		prefix string
    72→		scope  string
    73→	}{
    74→		{"socket", "socket"},
    75→		{"memoryDomain", "memoryDomain"},
    76→		{"core", "core"},
    77→		{"hwthread", "hwthread"},
    78→		{"cpu", "hwthread"},
    79→		{"accelerator", "accelerator"},
    80→	}
    81→
    82→	for _, p := range prefixes {
    83→		if len(name) > len(p.prefix) && name[:len(p.prefix)] == p.prefix {
    84→			id := name[len(p.prefix):]
    85→			if len(id) > 0 && id[0] >= '0' && id[0] <= '9' {
    86→				return p.scope, id
    87→			}
    88→		}
    89→	}
    90→
    91→	return name, ""
    92→}
    93→
    94→// writeParquetArchive writes rows to a Parquet file with Zstd compression.
    95→func writeParquetArchive(filename string, rows []ParquetMetricRow) error {
    96→	if err := os.MkdirAll(filepath.Dir(filename), CheckpointDirPerms); err != nil {
    97→		return fmt.Errorf("creating archive directory: %w", err)
    98→	}
    99→
   100→	f, err := os.OpenFile(filename, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, CheckpointFilePerms)
   101→	if err != nil {
   102→		return fmt.Errorf("creating parquet file: %w", err)
   103→	}
   104→	defer f.Close()
   105→
   106→	bw := bufio.NewWriterSize(f, 1<<20) // 1MB write buffer
   107→
   108→	writer := pq.NewGenericWriter[ParquetMetricRow](bw,
   109→		pq.Compression(&pq.Zstd),
   110→		pq.SortingWriterConfig(pq.SortingColumns(
   111→			pq.Ascending("cluster"),
   112→			pq.Ascending("hostname"),
   113→			pq.Ascending("metric"),
   114→			pq.Ascending("timestamp"),
   115→		)),
   116→	)
   117→
   118→	if _, err := writer.Write(rows); err != nil {
   119→		return fmt.Errorf("writing parquet rows: %w", err)
   120→	}
   121→
   122→	if err := writer.Close(); err != nil {
   123→		return fmt.Errorf("closing parquet writer: %w", err)
   124→	}
   125→
   126→	if err := bw.Flush(); err != nil {
   127→		return fmt.Errorf("flushing parquet file: %w", err)
   128→	}
   129→
   130→	return nil
   131→}
   132→
   133→// loadCheckpointFileFromDisk reads a JSON or binary checkpoint file and returns
   134→// a CheckpointFile. Used by the Parquet archiver to read checkpoint data
   135→// before converting it to Parquet format.
   136→func loadCheckpointFileFromDisk(filename string) (*CheckpointFile, error) {
   137→	f, err := os.Open(filename)
   138→	if err != nil {
   139→		return nil, err
   140→	}
   141→	defer f.Close()
   142→
   143→	ext := filepath.Ext(filename)
   144→	switch ext {
   145→	case ".json":
   146→		cf := &CheckpointFile{}
   147→		br := bufio.NewReader(f)
   148→		if err := json.NewDecoder(br).Decode(cf); err != nil {
   149→			return nil, fmt.Errorf("decoding JSON checkpoint %s: %w", filename, err)
   150→		}
   151→		return cf, nil
   152→
   153→	case ".bin":
   154→		br := bufio.NewReader(f)
   155→		var magic uint32
   156→		if err := binary.Read(br, binary.LittleEndian, &magic); err != nil {
   157→			return nil, fmt.Errorf("reading magic from %s: %w", filename, err)
   158→		}
   159→		if magic != snapFileMagic {
   160→			return nil, fmt.Errorf("invalid snapshot magic in %s: 0x%08X", filename, magic)
   161→		}
   162→		var fileFrom, fileTo int64
   163→		if err := binary.Read(br, binary.LittleEndian, &fileFrom); err != nil {
   164→			return nil, fmt.Errorf("reading from-timestamp from %s: %w", filename, err)
   165→		}
   166→		if err := binary.Read(br, binary.LittleEndian, &fileTo); err != nil {
   167→			return nil, fmt.Errorf("reading to-timestamp from %s: %w", filename, err)
   168→		}
   169→		cf, err := readBinaryLevel(br)
   170→		if err != nil {
   171→			return nil, fmt.Errorf("reading binary level from %s: %w", filename, err)
   172→		}
   173→		cf.From = fileFrom
   174→		cf.To = fileTo
   175→		return cf, nil
   176→
   177→	default:
   178→		return nil, fmt.Errorf("unsupported checkpoint extension: %s", ext)
   179→	}
   180→}
   181→
   182→// archiveCheckpointsToParquet reads checkpoint files for a host directory,
   183→// converts them to Parquet rows. Returns the rows and filenames that were processed.
   184→func archiveCheckpointsToParquet(dir, cluster, host string, from int64) ([]ParquetMetricRow, []string, error) {
   185→	entries, err := os.ReadDir(dir)
   186→	if err != nil {
   187→		return nil, nil, err
   188→	}
   189→
   190→	files, err := findFiles(entries, from, false)
   191→	if err != nil {
   192→		return nil, nil, err
   193→	}
   194→
   195→	if len(files) == 0 {
   196→		return nil, nil, nil
   197→	}
   198→
   199→	var rows []ParquetMetricRow
   200→
   201→	for _, checkpoint := range files {
   202→		filename := filepath.Join(dir, checkpoint)
   203→		cf, err := loadCheckpointFileFromDisk(filename)
   204→		if err != nil {
   205→			cclog.Warnf("[METRICSTORE]> skipping unreadable checkpoint %s: %v", filename, err)
   206→			continue
   207→		}
   208→
   209→		rows = flattenCheckpointFile(cf, cluster, host, "node", "", rows)
   210→	}
   211→
   212→	return rows, files, nil
   213→}
