    20→
    21→// Worker for either Archiving or Deleting files
    22→
    23→func CleanUp(wg *sync.WaitGroup, ctx context.Context) {
    24→	if Keys.Cleanup.Mode == "archive" {
    25→		// Run as Archiver
    26→		cleanUpWorker(wg, ctx,
    27→			Keys.Cleanup.Interval,
    28→			"archiving",
    29→			Keys.Cleanup.RootDir,
    30→			false,
    31→		)
    32→	} else {
    33→		if Keys.Cleanup.Interval == "" {
    34→			Keys.Cleanup.Interval = Keys.RetentionInMemory
    35→		}
    36→
    37→		// Run as Deleter
    38→		cleanUpWorker(wg, ctx,
    39→			Keys.Cleanup.Interval,
    40→			"deleting",
    41→			"",
    42→			true,
    43→		)
    44→	}
    45→}
    46→
    47→// cleanUpWorker takes simple values to configure what it does
    48→func cleanUpWorker(wg *sync.WaitGroup, ctx context.Context, interval string, mode string, cleanupDir string, delete bool) {
    49→	wg.Go(func() {
    50→
    51→		d, err := time.ParseDuration(interval)
    52→		if err != nil {
    53→			cclog.Fatalf("[METRICSTORE]> error parsing %s interval duration: %v\n", mode, err)
    54→		}
    55→		if d <= 0 {
    56→			return
    57→		}
    58→
    59→		ticker := time.NewTicker(d)
    60→		defer ticker.Stop()
    61→
    62→		for {
    63→			select {
    64→			case <-ctx.Done():
    65→				return
    66→			case <-ticker.C:
    67→				t := time.Now().Add(-d)
    68→				cclog.Infof("[METRICSTORE]> start %s checkpoints (older than %s)...", mode, t.Format(time.RFC3339))
    69→
    70→				n, err := CleanupCheckpoints(Keys.Checkpoints.RootDir, cleanupDir, t.Unix(), delete)
    71→
    72→				if err != nil {
    73→					cclog.Errorf("[METRICSTORE]> %s failed: %s", mode, err.Error())
    74→				} else {
    75→					if delete {
    76→						cclog.Infof("[METRICSTORE]> done: %d checkpoints deleted", n)
    77→					} else {
    78→						cclog.Infof("[METRICSTORE]> done: %d checkpoint files archived to parquet", n)
    79→					}
    80→				}
    81→			}
    82→		}
    83→	})
    84→}
    85→
    86→var ErrNoNewArchiveData error = errors.New("all data already archived")
    87→
    88→// CleanupCheckpoints deletes or archives all checkpoint files older than `from`.
    89→// When archiving, consolidates all hosts per cluster into a single Parquet file.
    90→func CleanupCheckpoints(checkpointsDir, cleanupDir string, from int64, deleteInstead bool) (int, error) {
    91→	if deleteInstead {
    92→		return deleteCheckpoints(checkpointsDir, from)
    93→	}
    94→
    95→	return archiveCheckpoints(checkpointsDir, cleanupDir, from)
    96→}
    97→
    98→// deleteCheckpoints removes checkpoint files older than `from` across all clusters/hosts.
    99→func deleteCheckpoints(checkpointsDir string, from int64) (int, error) {
   100→	entries1, err := os.ReadDir(checkpointsDir)
   101→	if err != nil {
   102→		return 0, err
   103→	}
   104→
   105→	type workItem struct {
   106→		dir            string
   107→		cluster, host  string
   108→	}
   109→
   110→	var wg sync.WaitGroup
   111→	n, errs := int32(0), int32(0)
   112→	work := make(chan workItem, Keys.NumWorkers)
   113→
   114→	wg.Add(Keys.NumWorkers)
   115→	for worker := 0; worker < Keys.NumWorkers; worker++ {
   116→		go func() {
   117→			defer wg.Done()
   118→			for item := range work {
   119→				entries, err := os.ReadDir(item.dir)
   120→				if err != nil {
   121→					cclog.Errorf("error reading %s/%s: %s", item.cluster, item.host, err.Error())
   122→					atomic.AddInt32(&errs, 1)
   123→					continue
   124→				}
   125→
   126→				files, err := findFiles(entries, from, false)
   127→				if err != nil {
   128→					cclog.Errorf("error finding files in %s/%s: %s", item.cluster, item.host, err.Error())
   129→					atomic.AddInt32(&errs, 1)
   130→					continue
   131→				}
   132→
   133→				for _, checkpoint := range files {
   134→					if err := os.Remove(filepath.Join(item.dir, checkpoint)); err != nil {
   135→						cclog.Errorf("error deleting %s/%s/%s: %s", item.cluster, item.host, checkpoint, err.Error())
   136→						atomic.AddInt32(&errs, 1)
   137→					} else {
   138→						atomic.AddInt32(&n, 1)
   139→					}
   140→				}
   141→			}
   142→		}()
   143→	}
   144→
   145→	for _, de1 := range entries1 {
   146→		entries2, e := os.ReadDir(filepath.Join(checkpointsDir, de1.Name()))
   147→		if e != nil {
   148→			err = e
   149→			continue
   150→		}
   151→
   152→		for _, de2 := range entries2 {
   153→			work <- workItem{
   154→				dir:     filepath.Join(checkpointsDir, de1.Name(), de2.Name()),
   155→				cluster: de1.Name(),
   156→				host:    de2.Name(),
   157→			}
   158→		}
   159→	}
   160→
   161→	close(work)
   162→	wg.Wait()
   163→
   164→	if err != nil {
   165→		return int(n), err
   166→	}
   167→	if errs > 0 {
   168→		return int(n), fmt.Errorf("%d errors happened while deleting (%d successes)", errs, n)
   169→	}
   170→	return int(n), nil
   171→}
   172→
   173→// archiveCheckpoints archives checkpoint files to Parquet format.
   174→// Produces one Parquet file per cluster: <cleanupDir>/<cluster>/<timestamp>.parquet
   175→func archiveCheckpoints(checkpointsDir, cleanupDir string, from int64) (int, error) {
   176→	clusterEntries, err := os.ReadDir(checkpointsDir)
   177→	if err != nil {
   178→		return 0, err
   179→	}
   180→
   181→	totalFiles := 0
   182→
   183→	for _, clusterEntry := range clusterEntries {
   184→		if !clusterEntry.IsDir() {
   185→			continue
   186→		}
   187→
   188→		cluster := clusterEntry.Name()
   189→		hostEntries, err := os.ReadDir(filepath.Join(checkpointsDir, cluster))
   190→		if err != nil {
   191→			return totalFiles, err
   192→		}
   193→
   194→		// Collect rows from all hosts in this cluster using worker pool
   195→		type hostResult struct {
   196→			rows  []ParquetMetricRow
   197→			files []string // checkpoint filenames to delete after successful write
   198→			dir   string   // checkpoint directory for this host
   199→		}
   200→
   201→		results := make(chan hostResult, len(hostEntries))
   202→		work := make(chan struct {
   203→			dir, host string
   204→		}, Keys.NumWorkers)
   205→
   206→		var wg sync.WaitGroup
   207→		errs := int32(0)
   208→
   209→		wg.Add(Keys.NumWorkers)
   210→		for w := 0; w < Keys.NumWorkers; w++ {
   211→			go func() {
   212→				defer wg.Done()
   213→				for item := range work {
   214→					rows, files, err := archiveCheckpointsToParquet(item.dir, cluster, item.host, from)
   215→					if err != nil {
   216→						cclog.Errorf("[METRICSTORE]> error reading checkpoints for %s/%s: %s", cluster, item.host, err.Error())
   217→						atomic.AddInt32(&errs, 1)
   218→						continue
   219→					}
   220→					if len(rows) > 0 {
   221→						results <- hostResult{rows: rows, files: files, dir: item.dir}
   222→					}
   223→				}
   224→			}()
   225→		}
   226→
   227→		go func() {
   228→			for _, hostEntry := range hostEntries {
   229→				if !hostEntry.IsDir() {
   230→					continue
   231→				}
   232→				dir := filepath.Join(checkpointsDir, cluster, hostEntry.Name())
   233→				work <- struct {
   234→					dir, host string
   235→				}{dir: dir, host: hostEntry.Name()}
   236→			}
   237→			close(work)
   238→			wg.Wait()
   239→			close(results)
   240→		}()
   241→
   242→		// Collect all rows and file info
   243→		var allRows []ParquetMetricRow
   244→		var allResults []hostResult
   245→		for r := range results {
   246→			allRows = append(allRows, r.rows...)
   247→			allResults = append(allResults, r)
   248→		}
   249→
   250→		if errs > 0 {
   251→			return totalFiles, fmt.Errorf("%d errors reading checkpoints for cluster %s", errs, cluster)
   252→		}
   253→
   254→		if len(allRows) == 0 {
   255→			continue
   256→		}
   257→
   258→		// Write one Parquet file per cluster
   259→		parquetFile := filepath.Join(cleanupDir, cluster, fmt.Sprintf("%d.parquet", from))
   260→		if err := writeParquetArchive(parquetFile, allRows); err != nil {
   261→			return totalFiles, fmt.Errorf("writing parquet archive for cluster %s: %w", cluster, err)
   262→		}
   263→
   264→		// Delete archived checkpoint files
   265→		for _, result := range allResults {
   266→			for _, file := range result.files {
   267→				filename := filepath.Join(result.dir, file)
   268→				if err := os.Remove(filename); err != nil {
   269→					cclog.Warnf("[METRICSTORE]> could not remove archived checkpoint %s: %v", filename, err)
   270→				} else {
   271→					totalFiles++
   272→				}
   273→			}
   274→		}
   275→
   276→		cclog.Infof("[METRICSTORE]> archived %d rows from %d files for cluster %s to %s",
   277→			len(allRows), totalFiles, cluster, parquetFile)
   278→	}
   279→
   280→	return totalFiles, nil
   281→}
