   106→func TestParquetArchiveRoundtrip(t *testing.T) {
   107→	tmpDir := t.TempDir()
   108→
   109→	// Create checkpoint files on disk (JSON format)
   110→	cpDir := filepath.Join(tmpDir, "checkpoints", "testcluster", "node001")
   111→	if err := os.MkdirAll(cpDir, 0o755); err != nil {
   112→		t.Fatal(err)
   113→	}
   114→
   115→	cf := &CheckpointFile{
   116→		From: 1000,
   117→		To:   1180,
   118→		Metrics: map[string]*CheckpointMetrics{
   119→			"cpu_load": {
   120→				Frequency: 60,
   121→				Start:     1000,
   122→				Data:      []schema.Float{0.5, 0.7, 0.9},
   123→			},
   124→			"mem_used": {
   125→				Frequency: 60,
   126→				Start:     1000,
   127→				Data:      []schema.Float{45.0, 46.0, 47.0},
   128→			},
   129→		},
   130→		Children: map[string]*CheckpointFile{
   131→			"socket0": {
   132→				Metrics: map[string]*CheckpointMetrics{
   133→					"mem_bw": {
   134→						Frequency: 60,
   135→						Start:     1000,
   136→						Data:      []schema.Float{100.0, 110.0, 120.0},
   137→					},
   138→				},
   139→				Children: make(map[string]*CheckpointFile),
   140→			},
   141→		},
   142→	}
   143→
   144→	// Write JSON checkpoint
   145→	cpFile := filepath.Join(cpDir, "1000.json")
   146→	data, err := json.Marshal(cf)
   147→	if err != nil {
   148→		t.Fatal(err)
   149→	}
   150→	if err := os.WriteFile(cpFile, data, 0o644); err != nil {
   151→		t.Fatal(err)
   152→	}
   153→
   154→	// Archive to Parquet
   155→	archiveDir := filepath.Join(tmpDir, "archive")
   156→	rows, files, err := archiveCheckpointsToParquet(cpDir, "testcluster", "node001", 2000)
   157→	if err != nil {
   158→		t.Fatal(err)
   159→	}
   160→	if len(files) != 1 || files[0] != "1000.json" {
   161→		t.Fatalf("expected 1 file, got %v", files)
   162→	}
   163→
   164→	parquetFile := filepath.Join(archiveDir, "testcluster", "1000.parquet")
   165→	if err := writeParquetArchive(parquetFile, rows); err != nil {
   166→		t.Fatal(err)
   167→	}
   168→
   169→	// Read back and verify
   170→	f, err := os.Open(parquetFile)
   171→	if err != nil {
   172→		t.Fatal(err)
   173→	}
   174→	defer f.Close()
   175→
   176→	stat, _ := f.Stat()
   177→	pf, err := pq.OpenFile(f, stat.Size())
   178→	if err != nil {
   179→		t.Fatal(err)
   180→	}
   181→
   182→	reader := pq.NewGenericReader[ParquetMetricRow](pf)
   183→	readRows := make([]ParquetMetricRow, 100)
   184→	n, err := reader.Read(readRows)
   185→	if err != nil && n == 0 {
   186→		t.Fatal(err)
   187→	}
   188→	readRows = readRows[:n]
   189→	reader.Close()
   190→
   191→	// We expect: cpu_load(3) + mem_used(3) + mem_bw(3) = 9 rows
   192→	if n != 9 {
   193→		t.Fatalf("expected 9 rows in parquet file, got %d", n)
   194→	}
   195→
   196→	// Verify cluster and hostname are set correctly
   197→	for _, r := range readRows {
   198→		if r.Cluster != "testcluster" {
   199→			t.Errorf("expected cluster=testcluster, got %s", r.Cluster)
   200→		}
   201→		if r.Hostname != "node001" {
   202→			t.Errorf("expected hostname=node001, got %s", r.Hostname)
   203→		}
   204→	}
   205→
   206→	// Verify parquet file is smaller than JSON (compression working)
   207→	if stat.Size() == 0 {
   208→		t.Error("parquet file is empty")
   209→	}
   210→
   211→	t.Logf("Parquet file size: %d bytes for %d rows", stat.Size(), n)
   212→}
